    "proxy-example.hbs": "    <button type='button' {{on 'click' (toggle-play-sound this.url)}}>\n      Play/Sound\n    </button>\n\n    {{#if this.sound.isLoaded}}\n      <p>the sound is loaded</p>\n    {{/if}}\n",
    "proxy-example.js": "export default class ProxyExample extends Component {\n  @service stereo;\n  @tracked url = 'https://streaming.koop.org/stream.aac';\n\n  get sound() {\n    return this.stereo.findSound(this.url);\n  }\n}",
    "queued.hbs": "\n    {{#if (sound-is-playing (current-sound))}}\n      <p>{{get (current-sound) 'url'}}</p>\n\n      <button type='button' {{on 'click' (stop-sound (current-sound))}}>\n        Stop\n      </button>\n    {{else}}\n      <button type='button' {{on 'click' this.playSound}}>\n        Play Queue\n      </button>\n    {{/if}}\n",
    "queued.js": "export default class Queued extends Component {\n  @service stereo;\n\n  @tracked identifier;\n  @tracked queue = [];\n\n  @action\n  async playSound() {\n    this.queue = [\n      '/sounds/attention.mp3',\n      '/sounds/internet-on-computers.mp3',\n      'https://streaming.koop.org/stream.aac',\n    ];\n\n    let sound = await this.playNext();\n    sound.audioElement.setAttribute(\n      'id',\n      `id-${Math.floor(Math.random() * 10000)}`\n    );\n\n    this.stereo.on('audio-ended', ({ sound }) => {\n      console.log(sound.audioElement);\n      this.playNext();\n    });\n  }\n\n  async playNext() {\n    let next = this.queue.shift();\n    if (next) {\n      let { sound } = await this.stereo.play(next);\n\n      return sound;\n    }\n  }\n}",
    "service-errors-silence-errors.hbs": "    <p>You can silence the thrown errors and handle them inline</p>\n    <div style='flex place-content-between'>\n      <button\n        {{on 'click' (fn this.togglePlaySound '/sounds/unplayable-scooby.au')}}\n        type='button'\n        class='ui-button'\n      >\n        {{#if this.sound.isPlaying}}\n          Pause\n        {{else}}\n          Play Sound\n        {{/if}}\n      </button>\n    </div>\n\n    {{#if this.error}}\n      <div class='px-1 py-2 text-sm text-danger'>{{this.error}}</div>\n    {{/if}}",
    "service-errors-silence-errors.js": "  @action\n  async togglePlaySound(url) {\n    this.error = false;\n\n    if (this.sound) {\n      this.sound.togglePause();\n    } else {\n      let { sound, error /* failures */ } = await this.stereo.play(url, {\n        silenceErrors: true,\n      });\n      this.sound = sound;\n      this.error = error;\n    }\n  }",
    "service-errors-try-catch.hbs": "    <p>Using a try/catch block with async/await</p>\n    <div>\n      <button\n        {{on\n          'click'\n          (perform this.playSoundTask '/sounds/unplayable-scooby.au')\n        }}\n        type='button'\n        class='ui-button'\n      >\n        {{#if this.playSoundTask.isRunning}}\n          Loading…\n        {{else if this.sound.isPlaying}}\n          Pause\n        {{else}}\n          Play Sound\n        {{/if}}\n      </button>\n    </div>\n\n    {{#if this.error}}\n      <div class='px-1 py-2 text-sm text-danger'>{{this.error}}</div>\n    {{/if}}",
    "service-errors-try-catch.js": "  playSoundTask = task(async (url) => {\n    this.error = false;\n\n    if (this.sound) {\n      this.sound.togglePause();\n    } else {\n      try {\n        let { sound /* error, failures */ } = await this.stereo.play(url);\n        this.sound = sound;\n      } catch (e) {\n        this.error = e.message;\n      }\n    }\n  });",
    "service-errors-try-then.hbs": "    <p>Using a try/then/catch on the promise</p>\n    <div>\n      <button\n        {{on 'click' (fn this.togglePlaySound '/sounds/unplayable-scooby.au')}}\n        type='button'\n        class='ui-button'\n      >\n        {{#if this.sound.isPlaying}}\n          Pause\n        {{else}}\n          Play Sound\n        {{/if}}\n      </button>\n    </div>\n\n    {{#if this.error}}\n      <div class='px-1 py-2 text-sm text-danger'>{{this.error}}</div>\n    {{/if}}",
    "service-errors-try-then.js": "  @action\n  togglePlaySound(url) {\n    this.error = false;\n\n    if (this.sound) {\n      this.sound.togglePause();\n    } else {\n      this.stereo\n        .play(url)\n        .then(({ sound /* error, failures */ }) => {\n          this.sound = sound;\n        })\n        .catch((e) => {\n          this.error = e.message;\n        });\n    }\n  }",
    "service-errors-wild-west.hbs": "    <p>This is what happens when you don't catch the error (open your console)</p>\n    <div>\n      <button\n        {{on 'click' (fn this.togglePlaySound '/sounds/unplayable-scooby.au')}}\n        type='button'\n        class='ui-button'\n      >\n        {{#if this.sound.isPlaying}}\n          Pause\n        {{else}}\n          Play Sound\n        {{/if}}\n      </button>\n    </div>\n\n    {{#if this.error}}\n      <div class='px-1 py-2 text-sm text-danger'>{{this.error}}</div>\n    {{/if}}",
    "service-errors-wild-west.js": "  @action\n  async togglePlaySound(url) {\n    this.error = false;\n\n    if (this.sound) {\n      this.sound.togglePause();\n    } else {\n      let { sound, error /* failures */ } = await this.stereo.play(url);\n\n      // error gets thrown and this will never happen. catch your errors, mang\n      this.sound = sound;\n      this.error[url] = error;\n    }\n  }",
